ALTER TABLE "catalog"."product_translation" RENAME COLUMN "title" TO "name";--> statement-breakpoint
CREATE VIEW "catalog"."product_list_view" AS (select "catalog"."product"."project_id", "catalog"."product"."id", "catalog"."product"."vendor_id", "catalog"."product"."handle", "catalog"."product"."published_at", "catalog"."product"."created_at", "catalog"."product"."updated_at", "catalog"."product"."deleted_at", "catalog"."product"."revision", "catalog"."product_translation"."locale", "catalog"."product_translation"."name" from "catalog"."product" inner join "catalog"."product_translation" on "catalog"."product_translation"."project_id" = "catalog"."product"."project_id" AND "catalog"."product_translation"."product_id" = "catalog"."product"."id");